import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useToast } from '../components/ui/Toast';

export default function PricingPage() {
  const { user, session, isPremium, invokeEdgeFunction } = useAuth();
  const brand = useBrand();
  const { showToast } = useToast();
  const navigate = useNavigate();

  async function handleCheckout() {
    if (!session) {
      navigate('/signup');
      return;
    }
    const { data, error } = await invokeEdgeFunction('create-checkout', {
      returnUrl: window.location.origin + '/app/account',
    });
    if (error) { showToast(error.message, true); return; }
    const url = (data as Record<string, string>)?.url;
    if (url) window.location.href = url;
  }

  const plans = [
    {
      name: 'Free',
      price: '$0',
      period: 'forever',
      features: [
        '2 resume tailors / month',
        '1 free try of each AI tool',
        '3 news briefings / week',
        'Basic resume templates',
        'Application tracking',
      ],
      cta: user ? 'Current Plan' : 'Sign Up Free',
      href: user ? undefined : '/signup',
      primary: false,
    },
    {
      name: 'Pro',
      price: '$9.99',
      period: '/month',
      features: [
        'Unlimited resume tailoring',
        'All 26 AI tools, unlimited',
        'Daily news briefings + podcast',
        'Voice interviews & negotiation',
        'All premium templates',
        'Priority support',
        'Analytics dashboard',
      ],
      cta: isPremium ? 'Current Plan' : 'Go Pro',
      onClick: isPremium ? undefined : handleCheckout,
      primary: true,
    },
  ];

  return (
    <div className="pricing-wrap" style={{ maxWidth: '800px', margin: '0 auto', padding: '3rem 1.5rem' }}>
      <div className="pricing-header" style={{ textAlign: 'center', marginBottom: '3rem' }}>
        <h1 style={{ fontSize: '2rem', marginBottom: '0.5rem', color: 'var(--text-primary)' }}>
          Simple, <span className="gradient-text">Transparent</span> Pricing
        </h1>
        <p style={{ color: 'var(--text-secondary)', fontSize: '1rem' }}>
          Start free, upgrade when you're ready
        </p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
        {plans.map(plan => (
          <div
            key={plan.name}
            className="glass-panel"
            style={{
              padding: '2rem',
              position: 'relative',
              borderColor: plan.primary ? brand.primaryColor : undefined,
              borderWidth: plan.primary ? '2px' : undefined,
            }}
          >
            {plan.primary && (
              <div style={{
                position: 'absolute',
                top: '-12px',
                left: '50%',
                transform: 'translateX(-50%)',
                background: brand.primaryColor,
                color: '#fff',
                padding: '0.2rem 0.75rem',
                borderRadius: 'var(--brutal-radius)',
                fontSize: '0.72rem',
                fontWeight: 700,
              }}>
                MOST POPULAR
              </div>
            )}

            <h3 style={{ fontSize: '1.25rem', margin: '0 0 0.5rem', color: 'var(--text-primary)' }}>{plan.name}</h3>
            <div style={{ marginBottom: '1.5rem' }}>
              <span style={{ fontSize: '2.5rem', fontWeight: 800, color: 'var(--text-primary)' }}>{plan.price}</span>
              <span style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>{plan.period}</span>
            </div>

            <ul style={{ listStyle: 'none', padding: 0, margin: '0 0 1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
              {plan.features.map(f => (
                <li key={f} style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  <i className="fa-solid fa-check" style={{ color: brand.primaryColor, marginRight: '0.5rem', fontSize: '0.7rem' }} />
                  {f}
                </li>
              ))}
            </ul>

            {plan.href ? (
              <button
                onClick={() => navigate(plan.href!)}
                className="btn primary-btn large-action-btn"
              >
                {plan.cta}
              </button>
            ) : (
              <button
                onClick={plan.onClick}
                disabled={!plan.onClick}
                className={`btn ${plan.primary && plan.onClick ? 'secondary-btn' : 'ghost-btn'} large-action-btn`}
              >
                {plan.cta}
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
